// Bundle src/browser/antibot-detect.ts → src/generated/antibot-detect.ts
// Produces an IIFE string constant for injection via addScriptToEvaluateOnNewDocument.
import { buildSync } from "esbuild";
import { readFileSync, writeFileSync, mkdirSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const rootDir = join(__dirname, "..");
const generatedDir = join(rootDir, "src", "generated");
mkdirSync(generatedDir, { recursive: true });

const DEV = process.env.NODE_ENV !== "production";
const pkg = JSON.parse(readFileSync(join(rootDir, "package.json"), "utf8"));
const version = pkg.version;

const result = buildSync({
  entryPoints: [join(rootDir, "src", "browser", "antibot-detect.ts")],
  bundle: true,
  format: "iife",
  platform: "browser",
  target: ["chrome90"],
  minify: !DEV,
  sourcemap: DEV ? "inline" : false,
  sourcesContent: DEV,
  write: false,
  tsconfig: join(rootDir, "src", "browser", "tsconfig.json"),
  banner: {
    js: `// Antibot Detector v${version} — ${new Date().toISOString()}`,
  },
});

const code = result.outputFiles[0].text;

const sizeKB = Math.round(Buffer.byteLength(code, "utf8") / 1024);
if (!DEV && sizeKB > 50) {
  console.error(`Antibot bundle too large: ${sizeKB}KB (limit: 50KB)`);
  process.exit(1);
}

writeFileSync(
  join(generatedDir, "antibot-detect.ts"),
  [
    "// AUTO-GENERATED by scripts/bundle-antibot.js — DO NOT EDIT",
    `// Source: src/browser/antibot-detect.ts (${sizeKB}KB)`,
    `export const ANTIBOT_DETECT_JS = ${JSON.stringify(code)};`,
    `export const ANTIBOT_DETECT_VERSION = ${JSON.stringify(version)};`,
    "",
  ].join("\n"),
);

console.log(`Generated src/generated/antibot-detect.ts (${sizeKB}KB, v${version})`);
